(function (global, factory) {
  if (typeof exports === 'object' && typeof module === 'object')
    module.exports = factory();
  else if (typeof define === 'function' && define.amd)
    define([], factory);
  else if (typeof exports === 'object')
    exports.printJS = factory();
  else
    global.printJS = factory();
})(window, function () {

  // Utility for browser detection
  const browserUtils = {
    isFirefox: () => typeof InstallTrigger !== 'undefined',
    isIE: () => navigator.userAgent.indexOf('MSIE') !== -1 || !!document.documentMode,
    isEdge: () => !browserUtils.isIE() && !!window.StyleMedia,
    isChrome: (w = window) => !!w.chrome,
    isSafari: () => Object.prototype.toString.call(window.HTMLElement).indexOf('Constructor') > 0 || navigator.userAgent.toLowerCase().includes('safari'),
    isIOSChrome: () => navigator.userAgent.toLowerCase().includes('crios')
  };

  // Modal utility for loading overlay
  const modal = {
    show: (options) => {
      const overlay = document.createElement('div');
      overlay.style = 'font-family:sans-serif; display:table; text-align:center; font-weight:300; font-size:30px; position:fixed; top:0; left:0; z-index:9990; width:100%; height:100%; background-color:rgba(255,255,255,0.9);';
      overlay.id = 'printJS-Modal';

      const container = document.createElement('div');
      container.style = 'display:table-cell; vertical-align:middle; padding-bottom:100px;';

      const closeBtn = document.createElement('div');
      closeBtn.id = 'printClose';
      closeBtn.className = 'printClose';

      const spinner = document.createElement('span');
      spinner.className = 'printSpinner';

      const message = document.createTextNode(options.modalMessage);

      container.appendChild(closeBtn);
      container.appendChild(spinner);
      container.appendChild(message);
      overlay.appendChild(container);
      document.body.appendChild(overlay);

      document.getElementById('printClose').addEventListener('click', modal.close);
    },

    close: () => {
      const overlay = document.getElementById('printJS-Modal');
      if (overlay) overlay.remove();
    }
  };

  // Validate type
  const supportedTypes = ['pdf', 'html', 'image', 'json', 'raw-html'];

  // Main printJS function
  function printJS(options, type) {
    const config = {
      printable: null,
      type: 'pdf',
      header: null,
      documentTitle: 'Document',
      showModal: false,
      modalMessage: 'Retrieving document...',
      frameId: 'printJS',
      onError: (err) => { throw err; },
      onLoadingStart: null,
      onLoadingEnd: null,
      onPrintDialogClose: () => {},
      onIncompatibleBrowser: () => {},
      css: null,
      style: null
    };

    // Process arguments
    if (typeof options === 'string') {
      config.printable = encodeURI(options);
      config.type = type || 'pdf';
    } else if (typeof options === 'object') {
      Object.assign(config, options);
    } else {
      throw new Error('Invalid printJS argument type. Expected string or object.');
    }

    if (!config.printable) throw new Error('Missing printable information.');
    if (!supportedTypes.includes(config.type)) throw new Error(`Unsupported print type: ${config.type}`);

    if (config.showModal) modal.show(config);
    if (config.onLoadingStart) config.onLoadingStart();

    const existingFrame = document.getElementById(config.frameId);
    if (existingFrame) existingFrame.remove();

    const iframe = document.createElement('iframe');
    iframe.id = config.frameId;
    iframe.style = 'visibility:hidden;height:0;width:0;position:absolute;border:0';
    if (browserUtils.isFirefox()) iframe.style = 'width:1px;height:100px;position:fixed;left:0;top:0;opacity:0;border-width:0;margin:0;padding:0';

    document.body.appendChild(iframe);

    switch (config.type) {
      case 'pdf':
        // Handle PDF
        if (browserUtils.isIE()) {
          window.open(config.printable, '_blank').focus();
          config.onIncompatibleBrowser();
        } else {
          iframe.src = config.printable;
          iframe.onload = () => iframe.contentWindow.print();
        }
        break;

      case 'html':
        // Print HTML element by ID (implementation omitted here for brevity)
        break;

      case 'image':
        // Print images (implementation omitted here for brevity)
        break;

      case 'json':
        // Print JSON data table (implementation omitted here for brevity)
        break;

      case 'raw-html':
        // Print raw HTML string (implementation omitted here for brevity)
        break;
    }
  }

  // Expose to window
  if (typeof window !== 'undefined') window.printJS = printJS;

  return printJS;
});